import{_ as r,o as t,c as s,j as a,a as n,a1 as d}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"自旋式直升机","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/杂项/自旋式直升机.md","filePath":"4.资源分区/6.技艺及称号/杂项/自旋式直升机.md"}'),o={name:"4.资源分区/6.技艺及称号/杂项/自旋式直升机.md"};function p(_,e,b,l,i,c){return t(),s("div",null,[...e[0]||(e[0]=[a("h1",{id:"自旋式直升机",tabindex:"-1"},[n("自旋式直升机 "),a("a",{class:"header-anchor",href:"#自旋式直升机","aria-label":'Permalink to "自旋式直升机"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调017")])])],-1),d('<h1 id="自旋式直升机-1" tabindex="-1">自旋式直升机 <a class="header-anchor" href="#自旋式直升机-1" aria-label="Permalink to &quot;自旋式直升机&quot;">​</a></h1><p>自旋式直升机<br> D+500<br> 经常见于各种非现实作品中，通过旋转长条形的物品来模仿直升机机翼从而起飞的技巧<br> 使用该技艺，需要你双手持用一把硬质长柄武器，或双持两把武器</p><p>【起飞】：<br> 以一个标准动作，你用武器在头顶旋转以产生上升气流，这使得你获得持续一轮的【普通飞行】能力，飞行速度等同于你的标准移动速度<br> 值得注意的是，此效果需要你每回合以一个标准动作维持，并且只会让你飞起来，你还需要用你的其他动作来移动<br> 注：如果ST允许，你也可以通过在头顶摇花手来飞行<br> 注：如果ST允许，你可以用任何可以旋转的肢体/物品来起飞，包括但不限于单臂大回旋/脖子大回旋/下体大回旋等</p><p>【闪电旋风劈】：<br> 在使用标准动作起飞或保持飞行的回合，你使用近战白刃武器进行攻击检定时，可以活用旋转带起的风力<br> 这使得你的攻击检定获得等同于你内在最高支线等级的【高速】，即d1c2b3a4s5</p><p>【落山机】：<br> 在使用标准动作起飞或保持飞行的回合，若你的移动速度允许你下落至地面攻击目标处，你可以主动选择下坠进行攻击，<br> 这使你这次近战白刃武器的攻击检定同时对你触及范围内的所有目标造成伤害<br> 此外，此次攻击你还可以选择附加等同于你内在最高支线等级的【燃烧】点数，即d1c2b3a4s5，反射豁免<br> 而你承受等量的不可豁免的【燃烧】点数<br> 注：你选择下坠的攻击需要你额外花费动作，本技艺仅保证你可以飞行</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=r(o,[["render",p]]);export{f as __pageData,m as default};
